sql:
SELECT a.asset_id, a.title, dm.title AS document_title, dm.author
FROM assets AS a
JOIN document_metadata AS dm ON a.asset_id = dm.asset_id;

SELECT AVG(tag_count)
FROM (
  SELECT asset_id, COUNT(tag_id) AS tag_count
  FROM asset_tags
  GROUP BY asset_id
);

SELECT a.asset_id, a.title, a.file_name, a.file_extension, im.width, im.height 
FROM assets a
JOIN image_metadata im ON a.asset_id = im.asset_id;

SELECT c1.user_id AS user1, c2.user_id AS user2, c1.asset_id
FROM collaborations c1
JOIN collaborations c2 ON c1.asset_id = c2.asset_id AND c1.user_id < c2.user_id;
